patch:
--- a/alu_32bit.v
+++ b/alu_32bit.v
@@ -1,18 +1,18 @@
 module alu_32bit(
   input [31:0] operand_x,
   input [31:0] operand_y,
   input [2:0] opcode,
   output [31:0] result
 );

-  always @(operand_x or operand_y) begin
+  always @(*) begin
     case (opcode)
       3'b000: result = operand_x + operand_y;
       3'b001: result = operand_x - operand_y;
       3'b010: result = operand_x & operand_y;
       3'b011: result = operand_x | operand_y;
       3'b100: result = operand_x ^ operand_y;
       default: result = 32'b0;
     endcase
   end
 endmodule

